const Subscriptions = require('../lib/subscriptions');

test('Constructor', ()=>{
    let subscriptions = new Subscriptions();

    expect(subscriptions.resource).toBe('/subscriptions');
});

test('Restore', ()=>{
    let subscriptions = new Subscriptions();

    expect(subscriptions.restore('123')).rejects.toBe('A API Asaas não permite restaurar assinaturas!');
});